templates.javascript:
function lengthOfLongestSubstring(s) {
    let map = {};
    let left = 0;
    let maxLen = 0;
    for (let right = 0; right < s.length; right++) {
        if (map[s[right]] !== undefined) {
            left = Math.max(left, map[s[right]] + 1);
        }
        map[s[right]] = right;
        maxLen = Math.max(maxLen, right - left + 1);
    }
    return maxLen;
}

